const ev = $json;
const p = ev.payload || {};
const q = [
  'macro regime shift',
  p.regime_new || p.regime || '',
  p.regime_prev ? 'from ' + p.regime_prev : '',
  ev.instrument || '',
  Object.keys(p).filter(k => /signal|trend|vol|rate/i.test(k)).map(k => k + ' ' + p[k]).join(' ')
].filter(Boolean).join(' ').trim();
return { json: { ...ev, rag_query: q.slice(0, 500) } };

parameters.query:
SELECT event_id, event_instrument, event_payload, book_slug, chunk_idx, title, content, score FROM (
    SELECT '{{ $('Build RAG query').first().json.event_id }}'::uuid AS event_id,
           '{{ $('Build RAG query').first().json.instrument || '' }}' AS event_instrument,
           '{{ JSON.stringify($('Build RAG query').first().json.payload) }}'::jsonb AS event_payload
) ev
CROSS JOIN LATERAL search_knowledge(('[' || '{{ $json.embedding.values.join(',') }}' || ']')::vector, 3);

parameters.jsCode:
const event = $('Build RAG query').first().json;
const regime = $('Fetch regime state').first()?.json || null;
const fredRowsRaw = $('Fetch FRED indicators').all().map(i => i.json);
const fredMap = {};
for (const r of fredRowsRaw) if (r?.indicator && !fredMap[r.indicator]) fredMap[r.indicator] = r;
const fredRows = Object.values(fredMap);
const chunks = items.map(i => i.json).filter(c => c.content);

const contextBlocks = chunks.slice(0, 3).map((c, i) =>
  `[${i + 1}] ${c.book_slug}/${c.chunk_idx} (score=${Number(c.score).toFixed(2)})
${c.content}`
).join('\n\n---\n\n');

const systemPrompt = `You are MacroAgent, a specialist trading analyst. Input: a macro regime event + CURRENT market state + FRED indicators. Output: ONE structured trade signal JSON — or {"skip": true, "reason": "..."} if no actionable setup.

Apply:
- Elder triple screen: HTF trend → MTF oscillator → LTF entry
- Wyckoff phases (accumulation/distribution/markup/markdown)
- Van Tharp R-multiple (1R stop, 2R+ target)
- Taleb antifragility: reject capped-upside + open-downside setups

MANDATORY CHECKS:
1. If event payload reflects regime that has ALREADY reversed vs current state (e.g., VIX spike resolved, regime back to normal) → skip with reason "regime reverted: event was X, current is Y"
2. If event is older than 72 hours AND current state shows no confirmation → skip with reason "stale event, no current confirmation"
3. If FRED indicators contradict event (e.g., event says risk-off but yield curve steepening + VIX low) → skip with reason "FRED contradicts event: [cite indicators]"

Signal schema — return ONLY this JSON, no commentary:
{
  "instrument": "SPX|DXY|XAUUSD|BTCUSDT|US10Y|...",
  "timeframe": "4H|1D|1W",
  "bias": "long|short|flat",
  "confidence": 0.0-1.0,
  "entry": number|null,
  "sl": number|null,
  "tp": [number]|null,
  "r_multiple": number|null,
  "rationale": "one sentence",
  "knowledge_refs": ["book_slug/chunk_idx", ...],
  "strategy_tag": "wyckoff-confluence|elder-triple|regime-divergence|fred-confluence|..."
}
Or: {"skip": true, "reason": "..."}`;

const regimeBlock = regime ? `CURRENT MARKET STATE (as of ${regime.regime_ts}):
macro_regime: ${regime.macro_regime}
risk_sentiment: ${regime.risk_sentiment}
fed_phase: ${regime.fed_phase}
vix_level: ${regime.vix_level}
dxy_trend: ${regime.dxy_trend}
yield_curve_spread: ${regime.yield_curve_spread}
confidence: ${regime.regime_confidence}
reasoning: ${regime.reasoning}` : 'CURRENT MARKET STATE: unavailable';

const fredBlock = fredRows.length
  ? 'FRED INDICATORS (latest):\n' + fredRows.map(r =>
      `  ${r.indicator}: ${r.value} (prev ${r.previous_value}, Δ ${r.change_pct}%) @ ${r.indicator_ts}`
    ).join('\n')
  : 'FRED INDICATORS: unavailable';

const userPrompt = `MACRO EVENT (historical trigger)
source: ${event.source}
event_ts: ${event.ts}
instrument: ${event.instrument || 'n/a'}
payload: ${JSON.stringify(event.payload)}

${regimeBlock}

${fredBlock}

RETRIEVED KNOWLEDGE
${contextBlocks}

Compare event vs current state AND FRED indicators. If conditions have reverted, event is stale, or FRED contradicts — skip. Otherwise output the signal JSON.`;

return [{
  json: {
    event_id: event.event_id,
    event_instrument: event.instrument,
    event_payload: event.payload,
    current_regime: regime,
    fred_indicators: fredRows,
    systemPrompt,
    userPrompt,
    knowledge_refs: chunks.slice(0, 3).map(c => `${c.book_slug}/${c.chunk_idx}`)
  }
}];

const ctx = $('Build Gemini Prompt').first().json;
const resp = items[0].json;
return [{ json: { ...resp, event_id: ctx.event_id, event_payload: ctx.event_payload, knowledge_refs: ctx.knowledge_refs } }];

const resp = items[0].json;
const ev = resp.event_payload || {};
let text = '';
try {
  text = resp.candidates[0].content.parts[0].text;
} catch (e) {
  return [{ json: { skip: true, reason: 'no candidates', event_id: resp.event_id } }];
}

text = text.replace(/```json\s*/gi, '').replace(/```/g, '').trim();

let signal;
try { signal = JSON.parse(text); }
catch (e) { return [{ json: { skip: true, reason: 'parse fail: ' + text.slice(0,100), event_id: resp.event_id } }]; }

if (signal.skip) {
  return [{ json: { skip: true, reason: signal.reason, event_id: resp.event_id } }];
}

const required = ['instrument', 'timeframe', 'bias', 'confidence'];
for (const k of required) {
  if (!(k in signal)) return [{ json: { skip: true, reason: 'missing ' + k, event_id: resp.event_id } }];
}

const effective_refs = (signal.knowledge_refs && signal.knowledge_refs.length ? signal.knowledge_refs : (resp.knowledge_refs || []));

const biasRu = signal.bias === 'long' ? 'ЛОНГ' : signal.bias === 'short' ? 'ШОРТ' : 'НЕЙТРАЛЬНО';
const biasEmoji = signal.bias === 'long' ? '\ud83d\udfe2' : signal.bias === 'short' ? '\ud83d\udd34' : '\u26aa';
const conf = Number(signal.confidence);
const confBar = '\u2588'.repeat(Math.round(conf * 5)) + '\u2591'.repeat(5 - Math.round(conf * 5));

let action = '';
if (signal.bias === 'long') {
  action = signal.entry ? `Рассмотреть покупку от $${signal.entry}` : 'Рассмотреть покупку на текущих';
  if (signal.sl) action += `, стоп $${signal.sl}`;
  if (signal.tp && signal.tp.length) action += `, цели: ${signal.tp.map(t => '$' + t).join(', ')}`;
} else if (signal.bias === 'short') {
  action = signal.entry ? `Рассмотреть продажу от $${signal.entry}` : 'Рассмотреть продажу на текущих';
  if (signal.sl) action += `, стоп $${signal.sl}`;
  if (signal.tp && signal.tp.length) action += `, цели: ${signal.tp.map(t => '$' + t).join(', ')}`;
} else {
  action = 'Без позиции, ждать подтверждения';
}

const tgText = `${biasEmoji} *${biasRu}* ${signal.instrument} (${signal.timeframe})

Уверенность: ${confBar} ${(conf * 100).toFixed(0)}%${signal.r_multiple ? '\nR-мульт: ' + signal.r_multiple + 'R' : ''}

*Почему:* ${signal.rationale || 'N/A'}

*Что делать:* ${action}

_Стратегия: ${signal.strategy_tag || 'macro'}_`;

return [{
    json: {
      skip: false,
    event_id: resp.event_id,
    instrument: signal.instrument,
    timeframe: signal.timeframe,
    bias: signal.bias,
    confidence: conf,
    entry: signal.entry ?? null,
    sl: signal.sl ?? null,
    tp: signal.tp || null,
    r_multiple: signal.r_multiple ?? null,
    rationale: { macro: signal.rationale || '' },
    knowledge_refs: effective_refs,
    strategy_tag: signal.strategy_tag || 'macro',
    telegram_text: tgText
  }
}];

